async function handleGmailCallback(request, env) {
  try {
    const url = new URL(request.url);
    const code = url.searchParams.get("code");
    const stateRaw = url.searchParams.get("state");
    if (!code || !stateRaw) return new Response("Missing code or state", { status: 400 });
    let state;
    try {
      state = JSON.parse(atob(stateRaw));
    } catch (e) {
      return new Response("Invalid state", { status: 400 });
    }
    const uid = state.uid;
    const clientId = env.GOOGLE_CLIENT_ID;
    const clientSecret = env.GOOGLE_CLIENT_SECRET;
    if (!clientId || !clientSecret) return new Response("OAuth not configured", { status: 500 });
    const tokenResp = await fetch("https://oauth2.googleapis.com/token", {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: new URLSearchParams({
        code,
        client_id: clientId,
        client_secret: clientSecret,
        redirect_uri: "https://branchlive-portal.shane-f58.workers.dev/api/gmail/callback",
        grant_type: "authorization_code"
      }).toString()
    });
    const tokenData = await tokenResp.json();
    if (tokenData.error) {
      return new Response(`Google said: ${tokenData.error} \u2014 ${tokenData.error_description || ""}`, { status: 400 });
    }
    const profileResp = await fetch("https://www.googleapis.com/oauth2/v2/userinfo", {
      headers: { "Authorization": `Bearer ${tokenData.access_token}` }
    });
    const profile = await profileResp.json();
    const email = profile.email || "";
    await env.DB.prepare(
      "UPDATE settings SET gmail_email = ?, gmail_refresh_token = ? WHERE user_id = ?"
    ).bind(email, tokenData.refresh_token || "", uid).run();
    return new Response(
      '<html><body style="font-family:Inter,sans-serif;background:#06060c;color:#f1f5f9;display:flex;align-items:center;justify-content:center;height:100vh;text-align:center"><div><h1 style="color:#00d4aa">\u2705 Gmail Connected!</h1><p style="color:#94a3b8">' + email + '</p><p style="color:#6b7d95">You can close this window. Emails will now send from your address.</p></div></body></html>',
      { headers: { "Content-Type": "text/html" } }
    );
  } catch (e) {
    console.error("Gmail callback error:", e);
    return new Response("OAuth failed. Please try again.", { status: 500 });
  }
}
