async function blogUniqueSlug(env, base, exceptId) {
  let slug = base || "post";
  let n = 1;
  while (true) {
    const q = exceptId ? env.DB.prepare("SELECT id FROM blog_posts WHERE slug = ? AND id != ?").bind(slug, exceptId) : env.DB.prepare("SELECT id FROM blog_posts WHERE slug = ?").bind(slug);
    const row = await q.first();
    if (!row) return slug;
    n++;
    slug = `${base}-${n}`;
    if (n > 999) return `${base}-${Date.now()}`;
  }
}
