        <div class="cp-next">
          <div class="nh">Hold Friday 2:30 demo slot &amp; send confirm-by-SMS with calendar hold.</div>
          <div class="nd"><button class="do-it" onclick="loadIntoCompose('draft','Holding Friday 2:30 demo slot, sending confirm + calendar hold, warm tone.')"><span class="glyph">\u2726</span> Do it</button></div>
        </div>
